+  it('disables the create button and shows loading while creating', async () => {
+    const user = userEvent.setup()
+    let resolveCreate: () => void = () => {}
+    const onCreate = vi.fn().mockImplementation(() => new Promise<void>((r) => { resolveCreate = r }))
